module RefModule (D, CLK, RESET, LOAD, Q);
input [7:0] D;
input CLK;
input RESET;
input LOAD;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RESET or posedge dbg_halt) begin
    if (RESET) begin
        Q <= 8'b00000000;
    end
    else if (LOAD) begin
        Q <= D;
    end
end

endmodule
